<template><div class="page-content"><PageHeader eyebrow="Service catalog" title="Applications" description="管理应用交付、运行状态与发布生命周期"><el-button type="primary" @click="$router.push('/applications/new')">＋ 创建应用</el-button></PageHeader><div class="metrics"><MetricCard title="全部应用" :value="store.items.length" icon="◇"/><MetricCard title="发布成功" :value="succeeded" icon="✓" tone="green"/><MetricCard title="运行中" :value="running" icon="↻" tone="blue"/><MetricCard title="失败" :value="failed" icon="!" tone="red"/></div><section class="surface table-card"><div class="toolbar"><div><el-input v-model="query" placeholder="搜索应用或仓库…" clearable/><el-select v-model="status" style="width:130px"><el-option label="全部状态" value=""/><el-option v-for="s in ['Succeeded','Running','Pending','Failed','analyzed']" :key="s" :label="s" :value="s"/></el-select></div><span>{{filtered.length}} applications</span></div><el-skeleton :loading="store.loading" animated :rows="6"><el-table v-if="paged.length" :data="paged"><el-table-column label="应用" min-width="250"><template #default="{row}"><div class="app-cell"><span>{{row.name[0].toUpperCase()}}</span><div><b>{{row.name}}</b><small>{{shortRepo(row.repo_url)}}</small></div></div></template></el-table-column><el-table-column label="技术栈" width="160"><template #default="{row}"><span class="tech">{{row.language}}</span><span class="tech">{{row.framework}}</span></template></el-table-column><el-table-column label="Namespace" prop="namespace" width="130"/><el-table-column label="状态" width="130"><template #default="{row}"><StatusBadge :status="row.latest_execution?.status||row.status"/></template></el-table-column><el-table-column label="最近执行" min-width="180"><template #default="{row}"><span class="mono run">{{row.latest_execution?.pipeline_run_name||'—'}}</span></template></el-table-column><el-table-column label="操作" width="170" fixed="right"><template #default="{row}"><el-button link @click="$router.push(`/applications/${row.id}`)">详情</el-button><el-button link :loading="deployingId===row.id" @click="deploy(row.id)">部署</el-button><el-dropdown trigger="click"><el-button link>更多 ···</el-button><template #dropdown><el-dropdown-menu><el-dropdown-item>查看配置</el-dropdown-item><el-dropdown-item>发布历史</el-dropdown-item></el-dropdown-menu></template></el-dropdown></template></el-table-column></el-table><EmptyState v-else title="没有找到应用" description="调整搜索条件，或者连接一个新的 GitHub 仓库。"><el-button type="primary" @click="$router.push('/applications/new')">创建应用</el-button></EmptyState></el-skeleton><footer v-if="filtered.length>pageSize"><el-pagination v-model:current-page="page" :page-size="pageSize" layout="prev, pager, next" :total="filtered.length"/></footer></section></div></template>
<script setup lang="ts">import{computed,onMounted,ref,watch}from'vue';import{ElMessage}from'element-plus';import{useApplicationStore}from'../stores/application';import{applicationApi}from'../api/application';import PageHeader from'../components/common/PageHeader.vue';import MetricCard from'../components/common/MetricCard.vue';import StatusBadge from'../components/common/StatusBadge.vue';import EmptyState from'../components/common/EmptyState.vue';const store=useApplicationStore(),query=ref(''),status=ref(''),page=ref(1),pageSize=10,deployingId=ref(0);const getStatus=(a:any)=>a.latest_execution?.status||a.status;const filtered=computed(()=>store.items.filter(a=>(!status.value||getStatus(a)===status.value)&&(!query.value||`${a.name}${a.repo_url}`.toLowerCase().includes(query.value.toLowerCase()))));const paged=computed(()=>filtered.value.slice((page.value-1)*pageSize,page.value*pageSize));const succeeded=computed(()=>store.items.filter(a=>getStatus(a)==='Succeeded').length),running=computed(()=>store.items.filter(a=>['Running','Pending'].includes(getStatus(a))).length),failed=computed(()=>store.items.filter(a=>getStatus(a)==='Failed').length);const shortRepo=(url:string)=>url.replace(/^https?:\/\/(www\.)?github\.com\//,'').replace(/\.git$/,'');watch([query,status],()=>page.value=1);onMounted(()=>store.load());async function deploy(id:number){deployingId.value=id;try{const run=await applicationApi.deploy(id);ElMessage.success(`已创建 ${run.pipeline_run_name}`);await store.load()}catch(e){ElMessage.error((e as Error).message)}finally{deployingId.value=0}}

</script>
<style scoped>.metrics{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:14px}.table-card{overflow:hidden}.toolbar{height:58px;padding:0 16px;display:flex;align-items:center;justify-content:space-between;border-bottom:1px solid var(--border-soft)}.toolbar>div{display:flex;gap:8px}.toolbar .el-input{width:230px}.toolbar>span{font-size:12px;color:var(--muted)}.app-cell{display:flex;align-items:center;gap:10px}.app-cell>span{width:31px;height:31px;display:grid;place-items:center;border-radius:8px;background:var(--primary-soft);color:#978bed;font-size:12px;font-weight:700}.app-cell b,.app-cell small{display:block}.app-cell b{font-size:12px}.app-cell small{font-size:12px;color:var(--muted);margin-top:4px}.tech{display:inline-block;padding:3px 6px;margin-right:4px;border:1px solid #2e3441;border-radius:5px;color:#8e97a8;font-size:12px}.run{font-size:12px;color:#7d8799}footer{display:flex;justify-content:flex-end;padding:12px 16px;border-top:1px solid var(--border-soft)}@media(max-width:1100px){.metrics{grid-template-columns:1fr 1fr}}</style>
